Steps:
[AUTH role=ORG_USER]
[GQL-OP list_coupons]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 20) {
      totalCount
      items { id systemName name label description couponCode endDate }
    }
  }
[GQL-EXEC list_coupons]
[GQL-CAPTURE list_coupons.data.promotionCoupons.totalCount → COUPON_TOTAL]
[GQL-CAPTURE list_coupons.data.promotionCoupons.items.0.couponCode → SAMPLE_COUPON]

[GQL-OP introspect_query]
  query {
    __type(name: "Query") {
      fields(includeDeprecated: false) {
        name
        args { name type { name kind ofType { name kind } } }
      }
    }
  }
[GQL-EXEC introspect_query]

[GQL-OP anon_query]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 5) {
      totalCount
      items { id couponCode systemName }
    }
  }
[GQL-EXEC anon_query]

[AUTH role=ORG_USER]
[GQL-OP wrong_store]
  query {
    promotionCoupons(storeId: "STORE_DOES_NOT_EXIST" first: 5) {
      totalCount
      items { id couponCode }
    }
  }
[GQL-EXEC wrong_store]

[GQL-OP missing_storeid]
  query {
    promotionCoupons(first: 10) {
      totalCount items { id couponCode }
    }
  }
[GQL-EXEC missing_storeid]

[AUTH role=ORG_USER]
[GQL-OP page1]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 2 after: "0") {
      totalCount items { id couponCode }
    }
  }
[GQL-EXEC page1]
[GQL-CAPTURE page1.data.promotionCoupons.totalCount → P1_TOTAL]
[GQL-CAPTURE page1.data.promotionCoupons.items.0.id → P1_ITEM0_ID]
[GQL-CAPTURE page1.data.promotionCoupons.items.1.id → P1_ITEM1_ID]
[GQL-OP page2]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 2 after: "2") {
      totalCount items { id couponCode }
    }
  }
[GQL-EXEC page2]
[GQL-CAPTURE page2.data.promotionCoupons.totalCount → P2_TOTAL]
[GQL-CAPTURE page2.data.promotionCoupons.items.0.id → P2_ITEM0_ID]

[AUTH role=ORG_USER]
[GQL-OP filter_query]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 100) {
      totalCount
      items { id systemName couponCode }
    }
  }
[GQL-EXEC filter_query]

[AUTH role=ORG_USER]
[GQL-OP with_culture]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" cultureName: "en-US" first: 5) {
      items { id systemName name label description }
    }
  }
[GQL-EXEC with_culture]
[GQL-CAPTURE with_culture.data.promotionCoupons.items.0.systemName → ITEM_SYSNAME]
[GQL-CAPTURE with_culture.data.promotionCoupons.items.0.name → ITEM_NAME_ENUS]
[GQL-OP without_culture]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 5) {
      items { id systemName name label description }
    }
  }
[GQL-EXEC without_culture]
[GQL-CAPTURE without_culture.data.promotionCoupons.items.0.systemName → ITEM_SYSNAME_NO_CULTURE]
[GQL-CAPTURE without_culture.data.promotionCoupons.items.0.name → ITEM_NAME_NO_CULTURE]

[AUTH role=ORG_USER]
[GQL-OP baseline]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 100) {
      totalCount items { id systemName couponCode }
    }
  }
[GQL-EXEC baseline]
[GQL-CAPTURE baseline.data.promotionCoupons.totalCount → BASELINE_TOTAL]
[GQL-CAPTURE baseline.data.promotionCoupons.items.0.id → DEACTIVATED_ID]
[GQL-CAPTURE baseline.data.promotionCoupons.items.0.systemName → DEACTIVATED_NAME]
[MANUAL] Operator: Admin → Marketing → Promotions → search by name "{{DEACTIVATED_NAME}}" (or filter to promotion whose id = {{DEACTIVATED_ID}}) → open detail blade → toggle Active=false → Save.
[GQL-OP after_deactivate]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 100) {
      totalCount items { id systemName couponCode }
    }
  }
[GQL-EXEC after_deactivate]
[GQL-CAPTURE after_deactivate.data.promotionCoupons.totalCount → POST_TOTAL]

[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id contact { organizationId } } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP setup_coupons]
  query {
    promotionCoupons(storeId: "{{STORE_ID}}" first: 1) {
      items { id couponCode }
    }
  }
[GQL-EXEC setup_coupons]
[GQL-CAPTURE setup_coupons.data.promotionCoupons.items.0.couponCode → COUPON_CODE]
[GQL-OP setup_prod]
  query { products(storeId: "{{STORE_ID}}" currencyCode: "USD" first: 1 filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3 price.USD:(0 TO) inStock_variations:true") { items { id } } }
[GQL-EXEC setup_prod]
[GQL-CAPTURE setup_prod.data.products.items.0.id → PRODUCT_ID]
[GQL-OP pre_clear]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC pre_clear]
[GQL-OP add_item]
  mutation { addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "{{PRODUCT_ID}}" quantity: 1 }) { id discountTotal { amount } } }
[GQL-EXEC add_item]
[GQL-OP apply_coupon]
  mutation {
    addCoupon(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" couponCode: "{{COUPON_CODE}}" }) {
      id
      coupons { code isAppliedSuccessfully }
      discountTotal { amount }
      total { amount }
      subTotal { amount }
    }
  }
[GQL-EXEC apply_coupon]

[AUTH role=ORG_USER]
